from multiprocessing import Pool

def make_transform(threshold):
    # BUG: closure over `threshold` — unpicklable on spawn start methods
    def transform(x):
        return x if x > threshold else 0
    return transform

def run(threshold, items):
    transform = make_transform(threshold)
    with Pool(4) as pool:
        results = pool.map(transform, items)
    return results

if __name__ == '__main__':
    run(5, list(range(20)))
